function log(target, methodName, descriptor) {
  const original = descriptor.value // ← оригинальная функция

  descriptor.value = function (...args) {
    // новая обёртка
  }
}

descriptor.value = function (...args) {
  console.log(`Вызов ${methodName}(${JSON.stringify(args)})`)

  const result = original.apply(this, args) // ← вызов оригинала

  console.log(`${methodName} → ${JSON.stringify(result)}`)
  return result
}

class Calculator {
  @log
  add(a, b) {
    return a + b
  }
}

const calc = new Calculator()
calc.add(2, 3)
// Вызов add([2,3])
// add → 5
